return [
  {
    json: {
      requestText: "Merhaba, ben Demo Öğrenci. Öğrenci numaram 20210002. Örnek Program 2 bölümünden mezun oldum. Geçici mezuniyet belgesi talep ediyorum.",
      operatorName: "Demo Operatör",
      source: "manual_demo",
      targetUniversity: "Demo Üniversitesi",
      requestLanguage: "tr"
    }
  }
];

function safeParse(value) {
  if (typeof value === 'object' && value !== null) return value;
  try {
    return JSON.parse(value);
  } catch (e) {
    const match = String(value || '').match(/\{[\s\S]*\}/);
    if (match) {
      try { return JSON.parse(match[0]); } catch (e2) {}
    }
  }
  return null;
}

const parsed = safeParse($json.response);

if (!parsed) {
  throw new Error('Ollama intake çıktısı JSON olarak ayrıştırılamadı. response=' + String($json.response).slice(0, 400));
}

return [{
  json: {
    ...$('Build Intake Payload').item.json,
    agent_intake: {
      documentType: parsed.documentType || 'student_certificate',
      studentName: parsed.studentName || '',
      studentNo: parsed.studentNo || '',
      programHint: parsed.programHint || '',
      language: parsed.language || 'tr',
      reason: parsed.reason || '',
      confidence: parsed.confidence ?? 0.7,
      missingFields: Array.isArray(parsed.missingFields) ? parsed.missingFields : []
    },
    ollamaIntakeRaw: $json.response
  }
}];

const students = [
  {
    studentNo: '210113416',
    fullName: 'Örnek Öğrenci 1',
    programName: 'Örnek Program',
    facultyName: 'Örnek Fakülte',
    status: 'active',
    gpa: 3.21,
    creditsCompleted: 108,
    graduationDate: null,
    expectedGraduationDate: '28-06-2026',
    militaryEligible: true,
    email: '210113416@example.edu',
    startTerm: '15-09-2022'
  },
  {
    studentNo: '20210002',
    fullName: 'Demo Öğrenci',
    programName: 'Örnek Program 2',
    facultyName: 'Örnek Fakülte',
    status: 'graduated',
    gpa: 3.46,
    creditsCompleted: 126,
    graduationDate: '28-06-2025',
    expectedGraduationDate: null,
    militaryEligible: false,
    email: '20210002@example.edu',
    startTerm: '15-09-2021'
  },
  {
    studentNo: '20230077',
    fullName: 'Örnek Öğrenci 2',
    programName: 'Örnek Program 3',
    facultyName: 'Örnek Fakülte',
    status: 'active',
    gpa: 2.94,
    creditsCompleted: 72,
    graduationDate: null,
    expectedGraduationDate: '28-06-2027',
    militaryEligible: true,
    email: '20230077@example.edu',
    startTerm: '15-09-2023'
  }
];

const wantedNo = String($json.agent_intake?.studentNo || '').trim();
const wantedName = String($json.agent_intake?.studentName || '').trim().toLowerCase();

let student = students.find(s => s.studentNo === wantedNo);

if (!student && wantedName) {
  student = students.find(s => s.fullName.toLowerCase() === wantedName);
}

if (!student) {
  student = {
    studentNo: wantedNo || 'UNKNOWN',
    fullName: $json.agent_intake?.studentName || 'Bilinmeyen Öğrenci',
    programName: $json.agent_intake?.programHint || 'Bilinmeyen Program',
    facultyName: 'Örnek Fakülte',
    status: 'unknown',
    gpa: null,
    creditsCompleted: null,
    graduationDate: null,
    expectedGraduationDate: null,
    militaryEligible: false,
    email: 'demo.student@example.edu',
    startTerm: null,
    syntheticRecord: true
  };
}

return [{
  json: {
    ...$json,
    student
  }
}];

const openDataContext = {
  universityName: 'Demo Üniversitesi',
  country: 'TÜRKİYE',
  sourceType: 'Public open data context',
  datasets: [
    {
      name: 'CU_SR_OPEN_DATA_CATALOG.csv',
      url: 'https://opendata.concordia.ca/datasets/sis/CU_SR_OPEN_DATA_CATALOG.csv'
    },
    {
      name: 'CU_SR_OPEN_DATA_CATALOG_DESC.csv',
      url: 'https://opendata.concordia.ca/datasets/sis/CU_SR_OPEN_DATA_CATALOG_DESC.csv'
    },
    {
      name: 'CU_SR_OPEN_DATA_TERM_SESS.csv',
      url: 'https://opendata.concordia.ca/datasets/sis/CU_SR_OPEN_DATA_TERM_SESS.csv'
    },
    {
      name: 'CU_SR_OPEN_DATA_DEPT_FAC_STRUC.csv',
      url: 'https://opendata.concordia.ca/datasets/sis/CU_SR_OPEN_DATA_DEPT_FAC_STRUC.csv'
    }
  ],
  normalizedPrograms: [
    {
      programName: 'Örnek Program',
      facultyName: 'İktisadi ve İdari Bilimler',
      level: 'Undergraduate',
      sampleCourses: ['SOEN 287', 'SOEN 341', 'SOEN 390']
    },
    {
      programName: 'Örnek Program',
      facultyName: 'İktisadi ve İdari Bilimler',
      level: 'Undergraduate',
      sampleCourses: ['COMP 248', 'COMP 249', 'COMP 352']
    },
    {
      programName: 'Örnek Program 2',
      facultyName: 'Örnek Fakülte',
      level: 'Undergraduate',
      sampleCourses: ['BTM 200', 'BTM 382', 'BTM 481']
    },
    {
      programName: 'Örnek Program 3',
      facultyName: 'İktisadi ve İdari Bilimler',
      level: 'Undergraduate',
      sampleCourses: ['MIAE 211', 'MIAE 313', 'MIAE 380']
    }
  ]
};

const programHint = ($json.agent_intake.programHint || $json.student.programName || '').toLowerCase();
let matchedProgram = openDataContext.normalizedPrograms.find(p => p.programName.toLowerCase() === programHint);

if (!matchedProgram) {
  matchedProgram = openDataContext.normalizedPrograms.find(p =>
    programHint && p.programName.toLowerCase().includes(programHint)
  ) || {
    programName: $json.student.programName || 'General Studies',
    facultyName: $json.student.facultyName || 'Demo Faculty',
    level: 'Undergraduate',
    sampleCourses: []
  };
}

return [{
  json: {
    ...$json,
    universityContext: {
      ...openDataContext,
      matchedProgram
    }
  }
}];

const docType = $json.agent_intake?.documentType || '';
const student = $json.student || {};

const studentStatus = String(student.status || '').trim().toLowerCase();

let eligible = false;
let reason = '';
let statusLabel = '';

if (docType === 'student_certificate') {
  eligible = studentStatus === 'active';
  reason = eligible
    ? 'Öğrencinin aktif kayıt durumu doğrulandı.'
    : 'Öğrenci aktif kayıtlı görünmediği için öğrenci durum belgesi düzenlenemedi.';
  statusLabel = 'ÖĞRENCİ DURUM BELGESİ';

} else if (docType === 'temporary_graduation') {
  eligible = studentStatus === 'graduated' && !!student.graduationDate;
  reason = eligible
    ? 'Öğrencinin mezuniyet bilgisi doğrulandı.'
    : 'Geçici mezuniyet belgesi düzenlenebilmesi için mezuniyet kaydının tamamlanmış olması gerekir.';
  statusLabel = 'GEÇİCİ MEZUNİYET BELGESİ';

} else if (docType === 'military_student_status') {
  eligible = studentStatus === 'active' && !!student.militaryEligible;
  reason = eligible
    ? 'Öğrencinin aktif kayıt durumu ve askerlik amaçlı kullanım uygunluğu doğrulandı.'
    : 'Askerlik için öğrenci durum belgesi düzenlenebilmesi için öğrencinin aktif kayıtlı ve uygun durumda olması gerekir.';
  statusLabel = 'ASKERLİK İÇİN ÖĞRENCİ DURUM BELGESİ';

} else {
  eligible = false;
  reason = 'Belge türü tanınamadı.';
  statusLabel = 'BELGE DURUMU BELİRSİZ';
}

return [{
  json: {
    ...$json,
    eligibility: {
      eligible,
      reason,
      statusLabel
    }
  }
}];

function pad(v) {
  return String(v).padStart(2, '0');
}

const now = new Date();
const issueDate = `${pad(now.getDate())}.${pad(now.getMonth() + 1)}.${now.getFullYear()}`;
const timestamp = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
const requestId = `STD-${timestamp}-${Math.floor(Math.random() * 900 + 100)}`;

const schema = {
  type: "object",
  properties: {
    title: { type: "string" },
    purposeLine: { type: "string" },
    body: { type: "string" },
    closingNote: { type: "string" }
  },
  required: ["title", "purposeLine", "body", "closingNote"]
};

const student = $json.student || {};
const program = $json.universityContext?.matchedProgram || {};
const docType = $json.agent_intake?.documentType || '';
const eligible = !!$json.eligibility?.eligible;
const reason = $json.eligibility?.reason || '';
const universityName = $json.universityContext?.universityName || 'Üniversite';

const prompt = `
Sen üniversite öğrenci işleri için resmi belge metni yazan bir ajansın.
Sadece JSON üret. Açıklama yazma. Markdown kullanma.

Bilgiler:
Belge türü: ${docType}
Uygunluk: ${eligible ? 'uygun' : 'uygun değil'}
Üniversite: ${universityName}
Öğrenci adı: ${student.fullName || ''}
Öğrenci no: ${student.studentNo || ''}
Program: ${program.programName || ''}
Fakülte: ${program.facultyName || ''}
Öğrenci durumu: ${student.status || ''}
Mezuniyet tarihi: ${student.graduationDate || '-'}
Belge tarihi: ${issueDate}
Gerekçe: ${reason}

Kurallar:
- Kısa, doğal ve resmi Türkçe kullan.
- Talimat cümlesi yazma.
- Tek paragraf yaz.
- Kötü kalıplar kullanma.
- Uygun değilse kısa ve nazik red metni yaz.

Başlıklar:
- student_certificate => ÖĞRENCİ DURUM BELGESİ
- temporary_graduation => GEÇİCİ MEZUNİYET BELGESİ
- military_student_status => ASKERLİK İÇİN ÖĞRENCİ DURUM BELGESİ

Ek kural:
- Uygun değilse title tam olarak TALEP SONUCU olsun.
- closingNote kısa olsun.
`;

return [{
  json: {
    ...$json,
    requestId,
    issueDate,
    writerPayload: {
      model: $json.ollama.model,
      prompt,
      stream: false,
      format: schema,
      options: {
        temperature: 0
      }
    }
  }
}];

function safeParse(value) {
  if (typeof value === 'object' && value !== null) return value;
  try {
    return JSON.parse(value);
  } catch (e) {
    const match = String(value || '').match(/\{[\s\S]*\}/);
    if (match) {
      try { return JSON.parse(match[0]); } catch (e2) {}
    }
  }
  return null;
}

const parsed = safeParse($json.response);

if (!parsed) {
  throw new Error('Ollama writer çıktısı JSON olarak ayrıştırılamadı. response=' + String($json.response).slice(0, 400));
}

return [{
  json: {
    ...$('Build Writer Payload').item.json,
    writerResult: {
      title: parsed.title || 'BELGE',
      purposeLine: parsed.purposeLine || '',
      body: parsed.body || '',
      closingNote: parsed.closingNote || ''
    },
    ollamaWriterRaw: $json.response
  }
}];

const schema = {
  type: "object",
  properties: {
    passed: { type: "boolean" },
    issues: {
      type: "array",
      items: { type: "string" }
    },
    correctedTitle: { type: "string" }
  },
  required: ["passed", "issues", "correctedTitle"]
};

const w = $json.writerResult;
const s = $json.student;
const p = $json.universityContext.matchedProgram;

const prompt = `
Sen belge kalite kontrol ajanısın.
Aşağıdaki alanları incele ve sadece JSON schema ile cevap ver.

Başlık: ${w.title}
Amaç satırı: ${w.purposeLine}
Gövde: ${w.body}
Öğrenci adı: ${s.fullName}
Öğrenci no: ${s.studentNo}
Program: ${p.programName}
Fakülte: ${p.facultyName}
Uygunluk gerekçesi: ${$json.eligibility.reason}

Kurallar:
- Başlık ile içerik uyumlu mu kontrol et.
- Boş veya eksik alan varsa issues içine yaz.
- correctedTitle alanına düzeltilmiş nihai başlığı ver.
- passed true yalnızca metin tutarlıysa olsun.
`;

return [{
  json: {
    ...$json,
    qcPayload: {
      model: $json.ollama.model,
      prompt,
      stream: false,
      format: schema,
      options: {
        temperature: 0
      }
    }
  }
}];

function safeParse(value) {
  if (typeof value === 'object' && value !== null) return value;
  try {
    return JSON.parse(value);
  } catch (e) {
    const match = String(value || '').match(/\{[\s\S]*\}/);
    if (match) {
      try { return JSON.parse(match[0]); } catch (e2) {}
    }
  }
  return null;
}

const parsed = safeParse($json.response);

if (!parsed) {
  return [{
    json: {
      ...$('Build QC Payload').item.json,
      qc: {
        passed: true,
        issues: ['QC çıktısı ayrıştırılamadı; varsayılan kabul edildi.'],
        correctedTitle: $('Build QC Payload').item.json.writerResult.title
      },
      ollamaQcRaw: $json.response
    }
  }];
}

return [{
  json: {
    ...$('Build QC Payload').item.json,
    qc: {
      passed: !!parsed.passed,
      issues: Array.isArray(parsed.issues) ? parsed.issues : [],
      correctedTitle: parsed.correctedTitle || $('Build QC Payload').item.json.writerResult.title
    },
    ollamaQcRaw: $json.response
  }
}];

const issueDate = $json.issueDate;
const requestId = $json.requestId;
const student = $json.student;
const program = $json.universityContext.matchedProgram;
const universityName = $json.universityContext.universityName;
const writer = $json.writerResult;
const qc = $json.qc || { passed: true, issues: [], correctedTitle: writer.title };

function esc(v) {
  return String(v ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const title = qc.correctedTitle || writer.title;
const qcText = qc.issues.length ? qc.issues.join(' | ') : 'Kalite kontrol uyarısı yok.';
const noteText = writer.closingNote || 'Bu çıktı otomatik hazırlanmıştır. Gerçek üretimde öğrenci işleri veritabanı ve resmi imza mekanizması ile entegre edilmelidir.';

const htmlDocument = `
<!doctype html>
<html lang="tr">
<head>
  <meta charset="utf-8" />
  <title>${esc(title)}</title>
  <style>
    body { font-family: Arial, Helvetica, sans-serif; margin: 40px; color: #111827; line-height: 1.6; }
    .page { max-width: 900px; margin: 0 auto; border: 1px solid #d1d5db; padding: 40px; }
    .topline { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; }
    .org { font-size: 14px; color: #374151; }
    .title { text-align: center; font-size: 24px; font-weight: bold; margin: 20px 0 10px; }
    .meta { margin-top: 8px; font-size: 14px; color: #4b5563; }
    .box { background: #f9fafb; border: 1px solid #e5e7eb; padding: 14px 16px; margin: 20px 0; }
    .footer { margin-top: 40px; font-size: 13px; color: #4b5563; }
    .sign { margin-top: 60px; text-align: right; }
    .small { font-size: 12px; color: #6b7280; }
  </style>
</head>
<body>
  <div class="page">
    <div class="topline">
      <div class="org">
        <strong>${esc(universityName)}</strong><br />
        Student Affairs Automation Demo
      </div>
      <div class="meta">
        Tarih: ${esc(issueDate)}<br />
        Belge No: ${esc(requestId)}
      </div>
    </div>

    <div class="title">${esc(title)}</div>

    <div class="box">
      <strong>Öğrenci Adı:</strong> ${esc(student.fullName)}<br />
      <strong>Öğrenci No:</strong> ${esc(student.studentNo)}<br />
      <strong>Program:</strong> ${esc(program.programName)}<br />
      <strong>Fakülte:</strong> ${esc(program.facultyName)}<br />
      <strong>Statü:</strong> ${esc(student.status)}
    </div>

    <p>${esc(writer.purposeLine)}</p>
    <p>${esc(writer.body)}</p>

    <p><strong>Uygunluk Sonucu:</strong> ${esc($json.eligibility.reason)}</p>
    <p><strong>Açık Veri Bağlamı:</strong> ${esc($json.universityContext.datasets.map(d => d.name).join(', '))}</p>

    <div class="footer">
      <div>Doğrulama Referansı: ${esc(requestId)}</div>
      <div class="small">${esc(noteText)}</div>
      <div class="small">QC: ${esc(qcText)}</div>
    </div>

    <div class="sign">
      <strong>Student Affairs Office</strong><br />
      <span class="small">Prepared automatically by n8n + Ollama workflow</span>
    </div>
  </div>
</body>
</html>
`.trim();

const plainTextDocument = [
  title,
  '',
  `Tarih: ${issueDate}`,
  `Belge No: ${requestId}`,
  '',
  `Öğrenci Adı: ${student.fullName}`,
  `Öğrenci No: ${student.studentNo}`,
  `Program: ${program.programName}`,
  `Fakülte: ${program.facultyName}`,
  '',
  writer.purposeLine,
  writer.body,
  '',
  `Uygunluk Sonucu: ${$json.eligibility.reason}`,
  `QC: ${qcText}`,
  `Doğrulama Referansı: ${requestId}`,
  noteText
].join('\n');

const fileName = `${$json.agent_intake.documentType}_${student.studentNo || 'unknown'}_${requestId}.html`;

return [{
  json: {
    ...$json,
    htmlDocument,
    plainTextDocument,
    fileName
  }
}];

return [{
  json: {
    status: 'completed',
    requestId: $json.requestId || 'unknown',
    university: $json.universityContext?.universityName || 'Concordia University',
    model: $json.ollama?.model || 'qwen2.5:3b-instruct',
    documentType: $json.agent_intake?.documentType || 'unknown',
    documentLabel: $json.eligibility?.statusLabel || 'completed',
    studentNo: $json.student?.studentNo || 'unknown',
    studentName: $json.student?.fullName || 'unknown',
    eligibility: $json.eligibility || {},
    message: 'Belge başarıyla oluşturuldu.'
  }
}];
